var _globalGraphData=null,_graphSelectedEdge=null,_graphSelectedNode=null;
async function graphView(){title('全局知识图谱','跨研究问题探索实体、机制邻域、路径、证据强度和可能分歧。');W.innerHTML+='<div class="global-graph-workspace"><div class="graph-topbar"><input id="graph-search" placeholder="搜索实体/药物/基因/通路"><select id="graph-view-mode"><option value="global">全局地图</option><option value="path">机制路径</option><option value="evidence">证据强度</option><option value="conflict">冲突地图</option></select><select id="graph-case-filter"></select><button class="button-sm" onclick="loadGraph()">重置</button><button class="button-sm" onclick="fitGraphCanvas()">适应画布</button></div><aside class="graph-filter-panel"><h3>过滤器</h3><label>实体类型<select id="graph-entity-type"></select></label><label><input id="graph-fulltext" type="checkbox"> 仅全文支持</label><label><input id="graph-conflict" type="checkbox"> 仅分歧线索</label><label>节点上限<select id="graph-node-limit"><option>80</option><option selected>150</option><option>250</option></select></label><div class="path-controls"><h4>机制路径</h4><input id="path-source" placeholder="起点"><input id="path-target" placeholder="终点"><button class="button-sm" onclick="loadGraphPath()">查看路径</button></div></aside><section class="graph-canvas-panel"><svg id="global-graph-svg" role="img" aria-label="Global Knowledge Map"></svg><div class="graph-legend">图例：圆形=基因/蛋白；圆角矩形=药物/化合物；六边形=通路；椭圆=生物过程；双边框=疾病；菱形=表型/结局。实线=全文支持，虚线=仅摘要/间接支持；边越粗证据越多。</div></section><aside class="graph-detail-side" id="graph-detail-side"><div class="empty">点击节点或边查看详情。</div></aside><footer class="graph-status" id="graph-status"></footer></div>';var f=await api('/api/graph/filters');document.querySelector('#graph-case-filter').innerHTML='<option value="">全部研究问题</option>'+f.cases.map(function(c){return'<option value="'+esc(c)+'">'+esc(c)+'</option>'}).join('');document.querySelector('#graph-entity-type').innerHTML='<option value="">全部实体类型</option>'+f.entity_types.map(function(t){return'<option value="'+esc(t)+'">'+esc(humanizeEntityType(t))+'</option>'}).join('');['graph-case-filter','graph-entity-type','graph-fulltext','graph-conflict','graph-node-limit','graph-view-mode'].forEach(function(id){document.querySelector('#'+id).onchange=loadGraph});document.querySelector('#graph-search').oninput=function(){renderGlobalGraph()};loadGraph()}
async function loadGraph(){var p=new URLSearchParams({limit_nodes:document.querySelector('#graph-node-limit').value,limit_edges:'260',case_id:document.querySelector('#graph-case-filter').value,entity_type:document.querySelector('#graph-entity-type').value});if(document.querySelector('#graph-fulltext').checked)p.set('has_fulltext','1');if(document.querySelector('#graph-conflict').checked)p.set('has_conflict','1');_globalGraphData=await api('/api/graph/overview?'+p);_graphSelectedEdge=null;_graphSelectedNode=null;renderGlobalGraph()}
function renderGlobalGraph(){var svg=document.querySelector('#global-graph-svg');if(!svg||!_globalGraphData)return;var q=(document.querySelector('#graph-search')?document.querySelector('#graph-search').value:'').toLowerCase(),nodes=_globalGraphData.nodes,edges=_globalGraphData.edges;if(q){var keep=new Set(nodes.filter(function(n){return(n.label||'').toLowerCase().indexOf(q)>=0}).map(function(n){return n.id}));edges=edges.filter(function(e){return keep.has(e.source)||keep.has(e.target)});keep=new Set([].concat(...edges.map(function(e){return[e.source,e.target]})));nodes=nodes.filter(function(n){return keep.has(n.id)||(n.label||'').toLowerCase().indexOf(q)>=0})}var w=900,h=560,cx=w/2,cy=h/2,r=Math.min(w,h)*.36,pos={};nodes.forEach(function(n,i){var a=(Math.PI*2*i/Math.max(1,nodes.length));pos[n.id]={x:cx+Math.cos(a)*r*(.55+(i%5)/10),y:cy+Math.sin(a)*r*(.55+(i%7)/12)}});var edgeHtml=edges.map(function(e){var a=pos[e.source],b=pos[e.target];if(!a||!b)return'';var full=(e.fulltext_evidence_count||0)>0,width=1+Math.min(6,e.evidence_count||0);return'<g class="graph-edge '+(_graphSelectedEdge===e.id?'selected':'')+'" data-graph-edge-id="'+esc(e.id)+'"><line x1="'+a.x+'" y1="'+a.y+'" x2="'+b.x+'" y2="'+b.y+'" stroke-width="'+width+'" stroke-dasharray="'+(full?'':'6 5')+'"></line><text x="'+((a.x+b.x)/2)+'" y="'+((a.y+b.y)/2)+'">'+esc(e.relation_label||e.relation)+'</text></g>'}).join('');var nodeHtml=nodes.map(function(n){var p=pos[n.id],size=18+Math.min(18,n.evidence_count||0),cls='graph-node type-'+String(n.entity_type||'unknown').replace(/[^a-z0-9_-]/gi,'_')+(_graphSelectedNode===n.id?' selected':'');return'<g class="'+cls+'" data-graph-node-id="'+esc(n.id)+'" transform="translate('+p.x+' '+p.y+')">'+nodeShapeSvg(n,size)+'<text y="'+(size+14)+'">'+esc(n.label||n.id)+'</text></g>'}).join('');svg.setAttribute('viewBox','0 0 '+w+' '+h);svg.innerHTML=edgeHtml+nodeHtml;document.querySelector('#graph-status').textContent='当前节点 '+nodes.length+' / 总节点 '+_globalGraphData.summary.total_nodes+' · 当前边 '+edges.length+' / 总边 '+_globalGraphData.summary.total_edges+' · cluster 仅用于 UI 布局，不写回 KG。'}
function nodeShapeSvg(n,size){var t=String(n.entity_type||'').toLowerCase();if(/compound|drug/.test(t))return'<rect x="'+(-size*1.4)+'" y="'+(-size*.7)+'" width="'+(size*2.8)+'" height="'+(size*1.4)+'" rx="8"></rect>';if(/pathway/.test(t))return'<polygon points="'+[-size+',0',-size/2+','+(-size*.85),size/2+','+(-size*.85),size+',0',size/2+','+(size*.85),-size/2+','+(size*.85)].join(' ')+'"></polygon>';if(/biological_process/.test(t))return'<ellipse rx="'+(size*1.4)+'" ry="'+(size*.8)+'"></ellipse>';if(/disease/.test(t))return'<circle r="'+size+'"></circle><circle r="'+(size-4)+'"></circle>';if(/phenotype|outcome/.test(t))return'<polygon points="0,'+(-size)+' '+size+',0 0,'+size+' '+(-size)+',0"></polygon>';if(/cell|tissue/.test(t))return'<rect x="'+(-size)+'" y="'+(-size*.55)+'" width="'+(size*2)+'" height="'+(size*1.1)+'" rx="5"></rect>';return'<circle r="'+size+'"></circle>'}
function selectGraphNode(id){_graphSelectedNode=id;_graphSelectedEdge=null;var n=(_globalGraphData.nodes||[]).find(function(x){return x.id===id});document.querySelector('#graph-detail-side').innerHTML='<h2>'+esc(n?n.label:id)+'</h2><p class="meta">'+esc(humanizeEntityType(n?n.entity_type:''))+' · 证据 '+esc(n?n.evidence_count:0)+'</p><div class="toolbar"><button class="button-sm" data-graph-neighborhood="upstream" data-graph-node-id="'+esc(id)+'">展开上游</button><button class="button-sm" data-graph-neighborhood="downstream" data-graph-node-id="'+esc(id)+'">展开下游</button><button class="button-sm" data-graph-neighborhood="both" data-graph-node-id="'+esc(id)+'">增加一跳</button><button class="button-sm" onclick="loadGraph()">恢复全局视图</button></div>';renderGlobalGraph()}
async function loadGraphNeighborhood(id,direction){var p=new URLSearchParams({depth:'1',limit:'120',direction:direction,case_id:document.querySelector('#graph-case-filter').value});_globalGraphData=await api('/api/graph/neighborhood/'+encodeURIComponent(id)+'?'+p);_globalGraphData.summary.total_nodes=_globalGraphData.summary.visible_nodes;_globalGraphData.summary.total_edges=_globalGraphData.summary.visible_edges;renderGlobalGraph()}
