var quickLabels=function(t){return[['支持','VALID'],['部分支持','PARTIAL'],['不支持','INVALID'],['无法判断','UNCLEAR']]};
var _crItem=null,_crAnnot=null,_crLabel='',_crDirty=false,_crActiveCase=null,_crActiveLayer=null;

async function review(metricsOnly){var x;try{x=await api('/api/review-metrics')}catch(e){title(isPharmaMode()?'证据判断':'Manual Review','Review data unavailable.');W.innerHTML+='<div class="empty">Review queue not available. Configure --review-root to enable manual review.</div>';return}title(metricsOnly?(isPharmaMode()?'审核统计':'Manual Review Metrics'):(isPharmaMode()?'证据判断工作台':'Interactive Manual Review'),isReviewerMode()?'审核目标：请判断系统抽取的机制关系是否被证据句支持。快捷键：V VALID, P PARTIAL, I INVALID, U UNCLEAR, S save。':(isPharmaMode()?'判断证据句是否支持系统提出的机制关系。':'Manual review labels assess extraction and triage quality. They do not constitute biological validation.'));if(metricsOnly){W.innerHTML+='<div class="card"><pre>'+esc(JSON.stringify(x,null,2))+'</pre></div>';return}
var counts=x.label_counts||x.final_label_counts||{};W.innerHTML+='<div class="review-workbench-card"><b>'+(isPharmaMode()?'判断目标':'审核目标')+'：</b> 请判断系统抽取的机制关系是否被证据句支持。如果主体、关系、客体、方向或上下文有明显错误，请标记为 PARTIAL 或 INVALID，并在 notes 说明。</div><div class="review-summary metric-grid" id="review-summary-grid"><div class="card metric"><strong>'+(x.reviewed_count+x.unreviewed_count)+'</strong>'+(isPharmaMode()?'待判断证据':'queue items')+'</div><div class="card metric"><strong>'+x.reviewed_count+'</strong>'+(isPharmaMode()?'已判断':'reviewed')+'</div><div class="card metric"><strong>'+x.unreviewed_count+'</strong>'+(isPharmaMode()?'未判断':'unreviewed')+'</div><div class="card metric"><strong>'+((x.reviewed_fraction||0)*100).toFixed(1)+'%</strong>'+(isPharmaMode()?'完成':'complete')+'</div><div class="card metric reviewer-only"><strong>'+(counts.VALID||counts.valid||0)+'/'+(counts.PARTIAL||counts.partial||0)+'/'+(counts.INVALID||counts.invalid||0)+'/'+(counts.UNCLEAR||counts.unclear||0)+'</strong>VALID / PARTIAL / INVALID / UNCLEAR</div></div><div class="review-toolbar reviewer-only"><a class="button" href="/api/review-export.csv">Export CSV</a><a class="button" href="/api/review-export.jsonl">Export JSONL</a><button class="button" onclick="recomputeMetrics()">Recompute Metrics</button></div><div class="review-workspace"><div class="case-review-sidebar" id="case-review-sidebar"><div class="loading">Loading cases\u2026</div></div><div class="review-layer-list" id="review-layer-list"><div class="empty">Select a case to see review layers.</div></div><div class="review-detail-panel" id="review-detail-panel"><div class="empty">Select a review item to annotate.</div></div></div>';loadReviewWorkspace()}

async function loadReviewWorkspace(){try{var ws=await api('/api/review-workspace')}catch(e){document.querySelector('#case-review-sidebar').innerHTML='<div class="error">Failed to load review workspace: '+esc(e.message)+'</div>';return}
var sidebar=document.querySelector('#case-review-sidebar');sidebar.innerHTML=ws.cases.map(function(c){var pct=c.total>0?((c.reviewed/c.total)*100).toFixed(0):'0';return'<div class="card clickable review-case-card'+(c.case_id===_crActiveCase?' active':'')+'" onclick="selectReviewCase(\''+esc(c.case_id)+'\')" id="rcase-'+esc(c.case_id)+'"><h3>'+esc(c.case_id)+'</h3><p class="meta">'+c.reviewed+'/'+c.total+' reviewed ('+pct+'%)</p></div>'}).join('')||'<div class="empty">No review cases found.</div>';
if(_crActiveCase){selectReviewCase(_crActiveCase)}else if(ws.cases.length>0){selectReviewCase(ws.cases[0].case_id)}}

async function selectReviewCase(caseId){_crActiveCase=caseId;_crActiveLayer=null;document.querySelector('#review-layer-list').innerHTML='<div class="loading">Loading layers\u2026</div>';document.querySelector('#review-detail-panel').innerHTML='<div class="empty">Select a layer and then a review item to annotate.</div>';document.querySelectorAll('.review-case-card').forEach(function(el){el.classList.toggle('active',el.id==='rcase-'+caseId)});
try{var layers=await api('/api/review-layers?case_id='+encodeURIComponent(caseId))}catch(e){document.querySelector('#review-layer-list').innerHTML='<div class="error">'+esc(e.message)+'</div>';return}
var layerList=document.querySelector('#review-layer-list');layerList.innerHTML='<h4>'+esc(caseId)+'</h4>'+(layers.layers||[]).map(function(l){var pct=l.total>0?((l.reviewed/l.total)*100).toFixed(0):'0';return'<div class="card clickable review-layer-card'+(l.layer_id===_crActiveLayer?' active':'')+'" onclick="selectReviewLayer(\''+esc(caseId)+'\',\''+esc(l.layer_id)+'\')" id="rlayer-'+esc(l.layer_id)+'"><h4>'+esc(l.label)+'</h4><div class="review-layer-stats"><span class="badge">'+l.reviewed+'/'+l.total+' reviewed</span>'+(l.valid>0?'<span class="badge review-label-badge label-valid">'+l.valid+' valid</span>':'')+(l.partial>0?'<span class="badge review-label-badge label-partial">'+l.partial+' partial</span>':'')+(l.invalid>0?'<span class="badge review-label-badge label-invalid">'+l.invalid+' invalid</span>':'')+(l.unreviewed>0?'<span class="badge warn">'+l.unreviewed+' unreviewed</span>':'')+'</div></div>'}).join('')||'<div class="empty">No layers for this case.</div>';
if(_crActiveLayer)selectReviewLayer(caseId,_crActiveLayer)}

async function selectReviewLayer(caseId,layerId){_crActiveLayer=layerId;document.querySelectorAll('.review-layer-card').forEach(function(el){el.classList.toggle('active',el.id==='rlayer-'+layerId)});
var p=new URLSearchParams({limit:'200',case_id:caseId,item_type:layerId}),d=await api('/api/review-items?'+p);var items=d.items||[];
var panel=document.querySelector('#review-detail-panel');panel.innerHTML='<h4>Review Items</h4><div class="review-item-list" id="review-item-list">'+items.map(function(x){var isRev=x.review_status==='reviewed',label=x.annotation?x.annotation.final_label:'';return'<article class="card clickable review-queue-item'+(isRev?' reviewed-item':'')+(x.review_item_id===(_crItem?_crItem.review_item_id:'')?' selected-item':'')+'" onclick="openReviewItem(\''+encodeURIComponent(x.review_item_id)+'\')" id="queue-'+esc(x.review_item_id)+'"><span class="badge '+(isRev?'':'warn')+'">'+(isRev?'Reviewed: '+esc(label):'Unreviewed')+'</span><span class="badge type reviewer-only">'+esc(shortId(x.review_item_id))+'</span><h3>'+esc(x.subject||x.paper_title||x.pmid||'Review item')+(x.relation?' \u2014 '+esc(x.relation):'')+' '+esc(x.object||'')+'</h3><p class="truncate">'+esc(x.evidence_sentence||x.claim_text||x.rejection_reason||'No preview')+'</p><p class="meta developer-only">'+esc(x.source_file)+':'+x.source_line+'</p>'+renderDeveloperDetails(x)+'</article>'}).join('')||'<div class="empty">No review items in this layer.</div>'}

async function openReviewItem(encoded){var x=await api('/api/review-item/'+encoded),a=x.annotation||{};_crItem=x;_crAnnot=a;_crLabel=a.final_label||'';_crDirty=false;var panel=document.querySelector('#review-detail-panel'),labels=quickLabels(x.item_type);
panel.innerHTML='<div class="review-detail-card"><div class="review-section"><span class="badge type">'+esc(x.item_type)+'</span><span class="badge type reviewer-only">'+esc(x.case_id||'')+'</span><span id="review-save-badge" class="badge '+(a.final_label?'':'warn')+'">'+(a.final_label?'Saved: '+esc(a.final_label):'Unsaved')+'</span><p class="badge warn review-disclaimer">Manual review labels assess extraction and triage quality. They do not constitute biological validation.</p><h3>'+esc(x.subject||'')+' '+esc(x.relation||'')+' '+esc(x.object||'')+'</h3><div class="extraction-grid"><div class="extraction-field"><strong>Subject</strong> '+esc(x.subject||'—')+'</div><div class="extraction-field"><strong>Relation</strong> '+esc(x.relation||'—')+'</div><div class="extraction-field"><strong>Object</strong> '+esc(x.object||'—')+'</div><div class="extraction-field"><strong>Direction</strong> '+esc(x.direction||'—')+'</div><div class="extraction-field"><strong>Context</strong> '+esc(x.context||x.context_text||'—')+'</div></div></div><div class="review-section"><h5 class="review-section-title">Evidence</h5><div class="evidence-box"><blockquote>'+esc(x.evidence_sentence||x.claim_text||x.rejection_reason||'No evidence preview')+'</blockquote><p class="meta">'+esc(x.paper_title||'')+' \u00b7 PMID '+esc(x.pmid||'\u2014')+' \u00b7 PMCID '+esc(x.pmcid||'\u2014')+'<span class="developer-only"> \u00b7 '+esc(x.source_file)+':'+x.source_line+'</span></p></div></div><div class="review-section"><h5 class="review-section-title">证据是否支持该机制关系？</h5><div id="review-quick-labels" class="judgment-button-row">'+labels.map(function(pair){return'<button data-label="'+pair[1]+'" class="review-choice'+(a.final_label===pair[1]?' active':'')+'" onclick="chooseReviewLabel(\''+pair[1]+'\',this)">'+pair[0]+'</button>'}).join('')+'</div></div><div id="error-diagnostics" class="review-section error-diagnostics" style="display:'+(['PARTIAL','INVALID'].indexOf(a.final_label)>=0?'block':'none')+'"><h5 class="review-section-title">错误诊断</h5><p class="meta">仅在“部分支持”或“不支持”时填写，用于说明主体、关系、方向、上下文或证据匹配问题。</p><div class="field-control"><label>错误类型</label><select id="ann-error_type">'+['','subject_error','relation_error','object_error','direction_error','context_error','evidence_not_supporting','too_vague','duplicate_or_noise'].map(function(v){return'<option value="'+v+'"'+(a.error_type===v?' selected':'')+'>'+esc(v||'未指定')+'</option>'}).join('')+'</select></div></div><details class="review-section professional-details"><summary>二级审核字段</summary><div class="secondary-field-grid">'+[['evidence_supported','Evidence supported',['','Yes','No','NA'],['','1','0','NA']],['subject_correct','Subject correct',['','Yes','No','NA'],['','1','0','NA']],['relation_correct','Relation correct',['','Yes','No','NA'],['','1','0','NA']],['object_correct','Object correct',['','Yes','No','NA'],['','1','0','NA']],['direction_correct','Direction correct',['','Yes','No','NA'],['','1','0','NA']],['context_captured','Context captured',['','Yes','No','NA'],['','1','0','NA']]].map(function(f){return'<div class="field-control"><label>'+f[1]+'</label><select id="ann-'+f[0]+'">'+f[3].map(function(v,i){return'<option value="'+v+'"'+(a[f[0]]===v?' selected':'')+'>'+f[2][i]+'</option>'}).join('')+'</select></div>'}).join('')+[['seed_relevance','Seed relevance',['','0','1','2','NA']],['mechanistic_usefulness','Mechanistic usefulness',['','0','1','2','NA']],['worth_followup','Worth follow-up',['','0','1','2','NA']]].map(function(f){return'<div class="field-control"><label>'+f[1]+'</label><select id="ann-'+f[0]+'">'+f[2].map(function(v){return'<option value="'+v+'"'+(a[f[0]]===v?' selected':'')+'>'+v+'</option>'}).join('')+'</select></div>'}).join('')+'</div></details>'+renderDeveloperDetails(x,"Review item raw / debug")+'<div class="review-section"><div class="review-actions"><div class="field-control field-control-full"><label>Notes</label><textarea id="ann-notes" rows="3" placeholder="Optional notes">'+esc(a.notes||'')+'</textarea></div><button class="button review-save-btn" onclick="saveReviewAnnotation(\''+encoded+'\')">Save Annotation</button><div id="review-save-message"></div></div></div></div>'}


function chooseReviewLabel(value,btn){_crLabel=value;_crDirty=true;document.querySelectorAll('#review-quick-labels .review-choice').forEach(function(b){b.classList.toggle('active',b.dataset.label===value)});var diag=document.querySelector('#error-diagnostics');if(diag)diag.style.display=(value==='PARTIAL'||value==='INVALID')?'block':'none';var badge=document.querySelector('#review-save-badge');if(badge){badge.textContent='Unsaved';badge.className='badge warn'}}

async function saveReviewAnnotation(encoded){if(!_crLabel){document.querySelector('#review-save-message').innerHTML='<span class="error">Select a primary judgment label first.</span>';return}
var body={final_label:_crLabel,reviewer_id:document.querySelector('#ann-reviewer')?document.querySelector('#ann-reviewer').value:'local_user',notes:document.querySelector('#ann-notes')?document.querySelector('#ann-notes').value:'',error_type:document.querySelector('#ann-error_type')?document.querySelector('#ann-error_type').value:''};
['evidence_supported','subject_correct','relation_correct','object_correct','direction_correct','context_captured','seed_relevance','mechanistic_usefulness','worth_followup'].forEach(function(f){var el=document.querySelector('#ann-'+f);if(el)body[f]=el.value});
try{var result=await apiPost('/api/annotation/'+encoded,body);_crDirty=false;var badge=document.querySelector('#review-save-badge');if(badge){badge.textContent='Saved: '+result.final_label;badge.className='badge'}document.querySelector('#review-save-message').innerHTML='<span class="badge saved-indicator">\u2713 Saved</span>';showToast('Annotation saved','success');var qe=document.querySelector('#queue-'+esc(result.review_item_id));if(qe){var be=qe.querySelector('.badge');if(be){be.textContent='Reviewed: '+result.final_label;be.classList.remove('warn')}qe.classList.add('reviewed-item')}updateReviewMetrics()}catch(e){document.querySelector('#review-save-message').innerHTML='<span class="error">'+esc(e.message)+'</span>';showToast('Save failed: '+e.message,'error')}}

async function updateReviewMetrics(){try{var m=await api('/api/review-metrics'),sg=document.querySelector('#review-summary-grid');if(sg){sg.innerHTML='<div class="card metric"><strong>'+(m.reviewed_count+m.unreviewed_count)+'</strong>queue items</div><div class="card metric"><strong>'+m.reviewed_count+'</strong>reviewed</div><div class="card metric"><strong>'+m.unreviewed_count+'</strong>unreviewed</div><div class="card metric"><strong>'+((m.reviewed_fraction||0)*100).toFixed(1)+'%</strong>complete</div>'}}catch(e){}}
async function recomputeMetrics(){await apiPost('/api/review-metrics/recompute');location.reload()}
function openReviewItemDirect(encoded){location.href='/review#'+encoded}
async function atlasLogout(){try{await apiPost('/api/logout');location.href='/login'}catch(e){showToast('Logout failed: '+e.message,'error')}}

// ════════════════ KEYBOARD ════════════════
document.addEventListener('keydown',function(e){if(['INPUT','TEXTAREA','SELECT'].indexOf(document.activeElement.tagName)>=0)return;var map={v:'VALID',p:'PARTIAL',i:'INVALID',u:'UNCLEAR'};if(map[e.key.toLowerCase()]&&document.querySelector('#review-quick-labels')){var val=map[e.key.toLowerCase()],btn=document.querySelector('#review-quick-labels .review-choice[data-label="'+val+'"]');if(btn)chooseReviewLabel(val,btn)}if(e.key.toLowerCase()==='s'&&document.querySelector('.review-save-btn')){document.querySelector('.review-save-btn').click()}});

// ════════════════ ROUTER ════════════════
async function route(){try{var p=decodeURIComponent(location.pathname),m;if(p==='/'||p==='/problems')return caseList();if(p==='/cases')return caseList();if((m=p.match(/^\/case\/(.+)$/)))return caseDetail(m[1]);if(p==='/evidence')return evidenceWorkspace();if(p==='/entities')return entities();if((m=p.match(/^\/entity\/(.+)$/)))return entityDetail(m[1]);if(p==='/chains')return chains();if((m=p.match(/^\/chain\/(.+)$/)))return chainPage(m[1]);if(p==='/triples')return triples();if((m=p.match(/^\/triple\/(.+)$/))){await triples();return openTriple(m[1])}if(p==='/graph')return graphView();if(p==='/conflicts')return conflicts();if(p==='/review')return review(false);if(p==='/progress')return progressWorkspace();if(p==='/metrics')return review(true);if(p==='/dev')return devWorkspace();if(p==='/help')return helpWorkspace();return caseList()}catch(e){console.error('Route error:',e);W.innerHTML='<div class="error"><h2>Unable to load view</h2><p>'+esc(e.message||'Unknown error')+'</p><p class="muted">Try refreshing the page. If the problem persists, the data source may be unavailable.</p></div>'}}

// ════════════════ BOOT ════════════════
// ════════════════ EVENT DELEGATION ════════════════
document.addEventListener('click',function(e){var copyEl=e.target.closest('[data-copy-text]');if(copyEl){e.preventDefault();e.stopPropagation();copyTextToClipboard(copyEl.dataset.copyText||"",copyEl);return}var graphEdgeEl=e.target.closest('[data-graph-edge-id]');if(graphEdgeEl){e.preventDefault();selectGraphEdge(graphEdgeEl.dataset.graphEdgeId);return}var graphNodeEl=e.target.closest('[data-graph-node-id][data-graph-neighborhood]');if(graphNodeEl){e.preventDefault();loadGraphNeighborhood(graphNodeEl.dataset.graphNodeId,graphNodeEl.dataset.graphNeighborhood);return}graphNodeEl=e.target.closest('[data-graph-node-id]');if(graphNodeEl){e.preventDefault();selectGraphNode(graphNodeEl.dataset.graphNodeId);return}var pathEl=e.target.closest('[data-path-source][data-path-target]');if(pathEl){e.preventDefault();prefillGraphPath(pathEl.dataset.pathSource,pathEl.dataset.pathTarget);return}var chainEl=e.target.closest('[data-chain-id]');if(chainEl){e.preventDefault();openChain(chainEl.dataset.chainId);return}var tripleEl=e.target.closest('[data-triple-id]');if(tripleEl){e.preventDefault();openTriple(tripleEl.dataset.tripleId);return}});

async function boot(){initModeSwitch();var errors=[];try{atlasSession=await api('/api/session');configureAllowedModes(atlasSession.allowed_modes)}catch(e){errors.push('Session: '+e.message);atlasSession={csrf_token:''};configureAllowedModes(Object.keys(ATLAS_MODES))}var userEl=document.querySelector('#current-user');if(atlasSession.user){userEl.innerHTML='<span>'+esc(atlasSession.user.display_name)+'</span> <button class="badge logout-button" type="button" onclick="atlasLogout()">Logout</button>'}else{userEl.innerHTML='<span class="muted">Local no-auth mode</span>'};try{var c=await api('/api/cases');cases=c.items;document.querySelector('#case-select').innerHTML+=[...cases].map(function(x){return'<option value="'+esc(x.case_id)+'">'+esc(x.case_id)+'</option>'}).join('')}catch(e){errors.push('Cases: '+e.message);cases=[]};document.querySelector('#case-select').onchange=function(e){if(e.target.value)location.href='/case/'+encodeURIComponent(e.target.value)};document.querySelector('#global-search').onkeydown=function(e){if(e.key==='Enter')location.href='/entities?q='+encodeURIComponent(e.target.value)};if(errors.length>0){var banner=document.createElement('div');banner.className='error-banner';banner.innerHTML='<strong>Startup warnings:</strong> '+errors.map(esc).join('; ')+' <button class=\"button-sm\" onclick=\"this.parentElement.remove()\">Dismiss</button>';document.querySelector('header').after(banner)};await route()}boot().catch(function(e){W.innerHTML='<div class="error">'+esc(e.message)+'</div>'});
